(window.webpackJsonp=window.webpackJsonp||[]).push([[1064],{1002:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">NumArray</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">__init__</span><span class=\\"hljs-params\\">(self, nums)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type nums: List[int]\\n        \\"\\"\\"</span>\\n        n=len(nums)\\n        numSums=[<span class=\\"hljs-number\\">0</span>]*(n+<span class=\\"hljs-number\\">1</span>)\\n        <span class=\\"hljs-comment\\"># numSums[0]=nums[0]</span>\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,n+<span class=\\"hljs-number\\">1</span>):\\n          numSums[i]=numSums[i<span class=\\"hljs-number\\">-1</span>]+nums[i<span class=\\"hljs-number\\">-1</span>]\\n        self.numSums=numSums\\n\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">sumRange</span><span class=\\"hljs-params\\">(self, i, j)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type i: int\\n        :type j: int\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        <span class=\\"hljs-comment\\"># print self.numSums</span>\\n        <span class=\\"hljs-keyword\\">return</span> self.numSums[j+<span class=\\"hljs-number\\">1</span>]-self.numSums[i]\\n\\n\\n<span class=\\"hljs-comment\\"># Your NumArray object will be instantiated and called as such:</span>\\n<span class=\\"hljs-comment\\"># obj = NumArray(nums)</span>\\n<span class=\\"hljs-comment\\"># param_1 = obj.sumRange(i,j)</span>\\n</code></pre>\\n"],"titleSlug":"range-sum-query-immutable","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 \xa0<code>nums</code>\uff0c\u6c42\u51fa\u6570\u7ec4\u4ece\u7d22\u5f15\xa0<code>i</code><em>\xa0</em>\u5230\xa0<code>j</code>\uff08<code>i\xa0\u2264\xa0j</code>\uff09\u8303\u56f4\u5185\u5143\u7d20\u7684\u603b\u548c\uff0c\u5305\u542b\xa0<code>i</code>\u3001<code>j\xa0</code>\u4e24\u70b9\u3002</p>\\n\\n<div class=\\"original__bRMd\\">\\n<div>\\n<p>\u5b9e\u73b0 <code>NumArray</code> \u7c7b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>NumArray(int[] nums)</code> \u4f7f\u7528\u6570\u7ec4 <code>nums</code> \u521d\u59cb\u5316\u5bf9\u8c61</li>\\n\\t<li><code>int sumRange(int i, int j)</code> \u8fd4\u56de\u6570\u7ec4 <code>nums</code> \u4ece\u7d22\u5f15\xa0<code>i</code><em>\xa0</em>\u5230\xa0<code>j</code><em>\uff08</em><code>i\xa0\u2264\xa0j</code>\uff09\u8303\u56f4\u5185\u5143\u7d20\u7684\u603b\u548c\uff0c\u5305\u542b\xa0<code>i</code>\u3001<code>j\xa0</code>\u4e24\u70b9\uff08\u4e5f\u5c31\u662f <code>sum(nums[i], nums[i + 1], ... , nums[j])</code>\uff09</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>\\n[\\"NumArray\\", \\"sumRange\\", \\"sumRange\\", \\"sumRange\\"]\\n[[[-2, 0, 3, -5, 2, -1]], [0, 2], [2, 5], [0, 5]]\\n<strong>\u8f93\u51fa\uff1a\\n</strong>[null, 1, -1, -3]\\n\\n<strong>\u89e3\u91ca\uff1a</strong>\\nNumArray numArray = new NumArray([-2, 0, 3, -5, 2, -1]);\\nnumArray.sumRange(0, 2); // return 1 ((-2) + 0 + 3)\\nnumArray.sumRange(2, 5); // return -1 (3 + (-5) + 2 + (-1)) \\nnumArray.sumRange(0, 5); // return -3 ((-2) + 0 + 3 + (-5) + 2 + (-1))\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= nums.length <= 10<sup>4</sup></code></li>\\n\\t<li><code>-10<sup>5</sup>\xa0<= nums[i] <=\xa010<sup>5</sup></code></li>\\n\\t<li><code>0 <= i <= j < nums.length</code></li>\\n\\t<li>\u6700\u591a\u8c03\u7528 <code>10<sup>4</sup></code> \u6b21 <code>sumRange</code><strong> </strong>\u65b9\u6cd5</li>\\n</ul>\\n</div>\\n</div>\\n","title":"303. \u533a\u57df\u548c\u68c0\u7d22 - \u6570\u7ec4\u4e0d\u53ef\u53d8","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Easy","lang":["python"],"uniqueID":"303"}')}}]);